import { useEffect, useState } from "react";
import "./LeaveAdmin.css";   // reusing same table styles

function EmployeeLeaveHistory() {
  const [requests, setRequests] = useState([]);

  const loggedInUser = JSON.parse(localStorage.getItem("loggedInUser"));

  useEffect(() => {
  const leaves = JSON.parse(localStorage.getItem("leaveRequests")) || [];

  const myLeaves = leaves.filter(
    (l) => l.empEmail === loggedInUser?.email
  );

  setRequests(myLeaves);
}, [loggedInUser?.email]);


  return (
    <div className="leave-admin-page">
      <h2>My Leave History</h2>

      {requests.length === 0 ? (
        <p className="no-requests">No Leave Applications Found</p>
      ) : (
        <table className="leave-table">
          <thead>
            <tr>
              <th>Leave Type</th>
              <th>From</th>
              <th>To</th>
              <th>Reason</th>
              <th>Applied</th>
              <th>Status</th>
            </tr>
          </thead>

          <tbody>
            {requests.map((req) => (
              <tr key={req.id}>
                <td>{req.leaveType}</td>
                <td>{req.fromDate}</td>
                <td>{req.toDate}</td>
                <td>{req.reason}</td>
                <td>{req.appliedDate}</td>

                <td>
                  <span
                    style={{
                      color:
                        req.status === "Approved"
                          ? "green"
                          : req.status === "Rejected"
                          ? "red"
                          : "#ff9800",
                      fontWeight: "bold",
                    }}
                  >
                    {req.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default EmployeeLeaveHistory;
